import 'package:dio/dio.dart';import 'package:uuid/uuid.dart';import '../config/api_config.dart';
Dio createDio(ApiConfig config)=>Dio(BaseOptions(baseUrl:config.baseUrl,connectTimeout:const Duration(seconds:10),receiveTimeout:const Duration(seconds:20),sendTimeout:const Duration(seconds:20)))..interceptors.add(InterceptorsWrapper(onRequest:(o,h){o.headers['X-Request-Id']=const Uuid().v4();h.next(o);}));
